76		for _, b := range beads {
77			events, err := store.Events(b.ID)
78			if err != nil {
79				continue
80			}
81			if next, ok := recentProviderConnectivityMinPowerFromEvents(events, now, floor, maxPower, ladder); ok {
82				if next >= maxPower && maxPower > 0 {
83					return baseMinPower, routeUnavailableReport(&b, next, maxPower, nil), true
84				}
85				if next > floor {
86					floor = next
87				}
88			}
89		}
90		if floor > baseMinPower {
91			return floor, agent.ExecuteBeadReport{}, true
92		}
93		return baseMinPower, agent.ExecuteBeadReport{}, false
94	}
