96	func recentProviderConnectivityMinPowerFromEvents(events []bead.BeadEvent, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, bool) {
97		if len(events) == 0 || ladder == nil {
98			return baseMinPower, false
99		}
100		floor := baseMinPower
101		var last recentRouteEvent
102		for _, ev := range events {
103			if ev.CreatedAt.IsZero() || now.Sub(ev.CreatedAt) > agent.ProviderUnavailableCooldown || ev.CreatedAt.After(now.Add(time.Minute)) {
104				continue
105			}
106			if route, ok := routeEventFromBeadEvent(ev); ok {
107				last = route
108				continue
109			}
110			if ev.Kind == "route-failure" {
111				route, ok := routeFailureEventFromBeadEvent(ev)
112				if !ok {
113					continue
114				}
115				if next, ok := nextFloorForRecentConnectivity(route.ActualPower, maxPower, ladder); ok && next > floor {
116					floor = next
117				}
118				continue
119			}
120			if ev.Kind == "execute-bead" && strings.EqualFold(strings.TrimSpace(ev.Summary), "execution_failed") && isProviderConnectivityEventBody(ev.Body) && last.Provider != "" {
121				if next, ok := nextFloorForRecentConnectivity(last.ActualPower, maxPower, ladder); ok && next > floor {
122					floor = next
123				}
124			}
125		}
126		return floor, floor > baseMinPower
127	}
