129	type recentRouteEvent struct {
130		Provider    string
131		Model       string
132		ActualPower int
133	}
134	
135	func routeEventFromBeadEvent(ev bead.BeadEvent) (recentRouteEvent, bool) {
136		if ev.Kind != "routing" && ev.Kind != "execution-routing-intent" {
137			return recentRouteEvent{}, false
138		}
139		var body map[string]any
140		if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
141			return recentRouteEvent{}, false
142		}
143		route := recentRouteEvent{
144			Provider:    firstNonEmptyString(body["resolved_provider"], body["actual_provider"], body["provider"]),
145			Model:       firstNonEmptyString(body["resolved_model"], body["actual_model"], body["model"]),
146			ActualPower: intFromAny(body["actual_power"]),
147		}
148		if route.Provider == "" {
149			return recentRouteEvent{}, false
150		}
151		return route, true
152	}
153	
154	func routeFailureEventFromBeadEvent(ev bead.BeadEvent) (recentRouteEvent, bool) {
155		var body map[string]any
156		if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
157			return recentRouteEvent{}, false
158		}
159		if reason := strings.TrimSpace(fmt.Sprint(body["outcome_reason"])); reason != "" && reason != agent.FailureModeProviderConnectivity {
160			return recentRouteEvent{}, false
161		}
162		route := recentRouteEvent{
163			Provider:    firstNonEmptyString(body["provider"]),
164			Model:       firstNonEmptyString(body["model"]),
165			ActualPower: intFromAny(body["actual_power"]),
166		}
167		if route.Provider == "" {
168			return recentRouteEvent{}, false
169		}
170		return route, true
171	}
