173	func nextFloorForRecentConnectivity(actualPower, maxPower int, ladder escalationFloorFinder) (int, bool) {
174		next, err := nextEscalationFloor(ladder, actualPower)
175		if err != nil {
176			return 0, false
177		}
178		if maxPower > 0 && next >= maxPower {
179			return next, true
180		}
181		return next, next > 0
182	}
