184	func isProviderConnectivityEventBody(body string) bool {
185		lower := strings.ToLower(body)
186		for _, marker := range []string{"dial tcp", "i/o timeout", "connection refused", "connection reset", "no route to host", "provider error"} {
187			if strings.Contains(lower, marker) {
188				return true
189			}
190		}
191		return false
192	}
