203	func intFromAny(value any) int {
204		switch v := value.(type) {
205		case int:
206			return v
207		case int64:
208			return int(v)
209		case float64:
210			return int(v)
211		case json.Number:
212			i, _ := v.Int64()
213			return int(i)
214		default:
215			return 0
216		}
217	}
