219	func resolvePowerFloor(powerClass policyescalation.PowerClass, ladder escalationFloorFinder) (int, bool) {
220		switch powerClass {
221		case policyescalation.PowerSmart:
222			floor, err := highestViableEscalationFloor(ladder)
223			if err != nil {
224				return 0, false
225			}
226			return floor, true
227		case policyescalation.PowerStandard:
228			first, err := nextEscalationFloor(ladder, 0)
229			if err != nil {
230				return 0, false
231			}
232			second, err := nextEscalationFloor(ladder, first)
233			if err != nil {
234				return first, true
235			}
236			return second, true
237		default:
238			return 0, false
239		}
240	}
