242	func zeroConfigInitialMinPower(b *bead.Bead, powerClass policyescalation.PowerClass, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
243		if powerClass == "" {
244			return baseMinPower, agent.ExecuteBeadReport{}, false
245		}
246		powerFloor, hasPowerFloor := resolvePowerFloor(powerClass, ladder)
247		if !hasPowerFloor && powerClass != policyescalation.PowerCheap {
248			return baseMinPower, routeUnavailableReport(b, baseMinPower, maxPower, fmt.Errorf("no viable routing floor for inferred powerClass %s", powerClass)), true
249		}
250		if powerFloor > baseMinPower {
251			if maxPower > 0 && powerFloor >= maxPower {
252				return baseMinPower, routeUnavailableReport(b, powerFloor, maxPower, nil), true
253			}
254			return powerFloor, agent.ExecuteBeadReport{}, false
255		}
256		return baseMinPower, agent.ExecuteBeadReport{}, false
257	}
