259	func routeUnavailableReport(b *bead.Bead, minPower, maxPower int, cause error) agent.ExecuteBeadReport {
260		beadID := ""
261		if b != nil {
262			beadID = b.ID
263		}
264		detail := fmt.Sprintf("route unavailable: no viable routing candidate satisfies requested MinPower %d", minPower)
265		if maxPower > 0 {
266			detail += fmt.Sprintf(" and MaxPower %d", maxPower)
267		}
268		if cause != nil {
269			detail += ": " + cause.Error()
270		}
271		return agent.ExecuteBeadReport{
272			BeadID:        beadID,
273			Status:        agent.ExecuteBeadStatusExecutionFailed,
274			Detail:        detail,
275			OutcomeReason: agent.FailureModeNoViableProvider,
276		}
277	}
278	
279	func runEscalatingPowerAttempts(
280		ctx context.Context,
281		initialMinPower int,
282		ladder escalationFloorFinder,
283		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
284		recordAttempt func(agent.ExecuteBeadReport),
285		perBeadTracker *policyescalation.PerBeadCostTracker,
286	) (agent.ExecuteBeadReport, error) {
287		minPower := initialMinPower
288		for {
289			report, err := attempt(ctx, minPower)
290			if recordAttempt != nil && report.BeadID != "" {
291				recordAttempt(report)
292			}
293			if perBeadTracker != nil {
294				perBeadTracker.Add(report.Harness, report.CostUSD)
295			}
296			if err != nil {
297				return report, err
298			}
299			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
300				return report, nil
301			}
302			if perBeadTracker != nil {
303				if detail, tripped := perBeadTracker.Tripped(); tripped {
304					report.Status = agent.ExecuteBeadStatusExecutionFailed
305					report.Detail = detail
306					report.CostUSD = perBeadTracker.Spent()
307					return report, nil
308				}
309			}
310			var nextPower int
311			if report.ActualPower > 0 {
312				// Evidence-driven retry: bump MinPower one above the actual power
313				// the previous route ran at. Profile reselection in the caller's
314				// attempt callback moves to a stronger policy band only when the
315				// new floor exceeds the current band's MaxPower; otherwise the
316				// same policy intent is preserved so DDx does not duplicate
317				// Fizeau policy bounds as initial dispatch floors.
318				nextPower = report.ActualPower + 1
319			} else {
320				next, nextErr := nextEscalationFloor(ladder, minPower)
321				if nextErr != nil {
322					return report, nil
323				}
324				nextPower = next
325			}
326			minPower = nextPower
327		}
328	}
